<template>
  <view class="page-container">
    <text class="page-title">居家护理手册</text>

    <!-- 筛选栏 -->
    <view class="filter-box">
      <u-dropdown>
        <u-dropdown-item v-model="filterCategory" :options="categoryOptions" @change="onFilterChange"></u-dropdown-item>
      </u-dropdown>
    </view>

    <!-- 加载状态 -->
    <view v-if="loading" class="loading-state">
      <u-loading-icon mode="circle"></u-loading-icon>
      <text class="loading-text">加载中...</text>
    </view>

    <!-- 护理内容 -->
    <u-collapse v-else v-model="active" accordion>
      <u-collapse-item
        v-for="item in list"
        :key="item.id"
        :title="item.title"
        :name="item.id"
      >
        <view class="collapse-content">
          <text class="content-text">{{ item.content }}</text>
          <text class="update-time">更新时间：{{ formatDate(item.updateTime) }}</text>
        </view>
      </u-collapse-item>
    </u-collapse>

    <!-- 空状态 -->
    <u-empty v-if="!loading && list.length === 0" mode="data" description="暂无护理手册"></u-empty>

    <!-- 工具下载 -->
    <view class="download-box">
      <u-button type="primary" @click="downloadChecklist" :loading="downloadingChecklist">
        下载护理清单
      </u-button>
      <u-button type="primary" @click="downloadRecordForm" :loading="downloadingRecord" class="ml-2">
        下载观察记录表
      </u-button>
    </view>
  </view>
</template>

<script setup lang="ts">
import { ref, onMounted, watch } from 'vue'
import request from '@/utils/request'

// 筛选条件
const filterCategory = ref('all')

// 展开的面板
const active = ref<string | number | Array<string | number>>([])

// 筛选项
const categoryOptions = ref<{ text: string; value: string }[]>([])

// 列表数据
const list = ref<any[]>([])
const loading = ref(false)
const downloadingChecklist = ref(false)
const downloadingRecord = ref(false)

// 格式化日期
const formatDate = (dateStr: string) => {
  if (!dateStr) return '-'
  const date = new Date(dateStr)
  return date.toLocaleDateString('zh-CN')
}

// 获取分类选项
const fetchCategories = async () => {
  try {
    const res = await request.get('/api/resource/rehab/manuals/categories')
    const data = res.data || res.data || {}

    if (data.categories && Array.isArray(data.categories)) {
      categoryOptions.value = [
        { text: '全部类别', value: 'all' },
        ...data.categories.map((item: any) => ({
          text: item.text || item.name,
          value: item.value || item.code
        }))
      ]
    }
  } catch (error) {
    uni.__f__('error','at pages/resource/rehab/HomeCareManual.vue:90','获取分类选项失败:', error)
    // 使用默认选项
    categoryOptions.value = [
      { text: '全部类别', value: 'all' },
      { text: '饮食指导', value: 'diet' },
      { text: '皮肤护理', value: 'skin' },
      { text: '康复训练', value: 'rehab' },
      { text: '用药指导', value: 'medication' },
      { text: '心理支持', value: 'psychology' }
    ]
  }
}

// 获取护理手册列表
const fetchManuals = async () => {
  loading.value = true
  try {
    const params: Record<string, any> = {}
    if (filterCategory.value !== 'all') params.category = filterCategory.value

    const res = await request.get('/api/resource/rehab/manuals', { params })
    const responseData = res.data || res.data || {}
    list.value = responseData.manuals || []
  } catch (error) {
    uni.__f__('error','at pages/resource/rehab/HomeCareManual.vue:114','获取护理手册失败:', error)
    list.value = []
    uni.showToast({ title: '加载失败，请重试', icon: 'none' })
  } finally {
    loading.value = false
  }
}

// 筛选条件变化
const onFilterChange = () => {
  fetchManuals()
}

// 下载护理清单
const downloadChecklist = async () => {
  downloadingChecklist.value = true
  try {














    

    uni.showToast({ title: '请在H5端下载', icon: 'none' })

  } catch (error) {
    uni.__f__('error','at pages/resource/rehab/HomeCareManual.vue:150','下载失败:', error)
    uni.showToast({ title: '下载失败', icon: 'none' })
  } finally {
    downloadingChecklist.value = false
  }
}

// 下载观察记录表
const downloadRecordForm = async () => {
  downloadingRecord.value = true
  try {














    

    uni.showToast({ title: '请在H5端下载', icon: 'none' })

  } catch (error) {
    uni.__f__('error','at pages/resource/rehab/HomeCareManual.vue:180','下载失败:', error)
    uni.showToast({ title: '下载失败', icon: 'none' })
  } finally {
    downloadingRecord.value = false
  }
}

// 监听筛选条件变化
watch([filterCategory], () => {
  // onFilterChange is called by @change event of dropdown
})

// 组件挂载时初始化
onMounted(() => {
  fetchCategories()
  fetchManuals()
})
</script>

